with:
  # Handle place of origin or birth and optionally enrich with facts about that place.
          origin_obj = None
          if "origin" in info:
              origin_obj = info.pop("origin")[0]
              parts.append(f"originates from {origin_obj}")
          elif "birthPlace" in info:
              origin_obj = info.pop("birthPlace")[0]
              # If we already added a birth date/year, attach place with 'in'.
              if any(p.startswith("was born") for p in parts):
                  parts.append(f"in {origin_obj}")
              else:
                  parts.append(f"was born in {origin_obj}")

          # If the origin/birth place itself has descriptive predicates (e.g., language, capital),
          # incorporate them into the same sentence.
          if origin_obj and origin_obj in all_info:
              related_clauses = []
              ent_info = all_info[origin_obj]
              if "language" in ent_info:
                  langs = _join_items(ent_info["language"])
                  related_clauses.append(f"where {langs} is spoken")
              if "officialLanguage" in ent_info:
                  langs = _join_items(ent_info["officialLanguage"])
                  related_clauses.append(f"where the official language is {langs}")
              if "capital" in ent_info:
                  caps = _join_items(ent_info["capital"])
                  related_clauses.append(f"where the capital is {caps}")
              if related_clauses:
                  parts.append(", ".join(related_clauses))
